const PRIZE_IMGS = [F1, F2, F3];

function FotoCarousel() {
  const [active, setActive] = useState(0);
  const [imgError, setImgError] = useState([false,false,false]);

  return (
    <div className="foto-wrap">
      <div className="foto-badge">📱 iPhone 17e</div>
      {imgError[active] ? (
        <div className="foto-main-placeholder">📱</div>
      ) : (
        <img
          className="foto-main"
          src={PRIZE_IMGS[active]}
          alt="iPhone"
          onError={()=>setImgError(p=>{const n=[...p];n[active]=true;return n})}
        />
      )}
      <div className="foto-thumbs">
        {PRIZE_IMGS.map((src,i)=>(
          imgError[i]
            ? <div key={i} className={`foto-thumb-placeholder${active===i?" on":""}`} onClick={()=>setActive(i)}>📱</div>
            : <img key={i} className={`foto-thumb${active===i?" on":""}`} src={src} alt="" onClick={()=>setActive(i)} onError={()=>setImgError(p=>{const n=[...p];n[i]=true;return n})} />
        ))}
      </div>

    </div>
  );
}

